//! wf-clean: a clean-room reimplementation of the tamarin-prover wellformedness
//! checker, derived purely from black-box oracle behavior. See
//! workspace/BEHAVIOR.md for the inferred behavioral spec.


pub mod checks;
pub mod formula;
pub mod pretty;
pub mod report;

