1041	/// Build the rule-node label Doc — HS `ruleLabelM` (Dot.hs:330-338):
1042	/// `prettyNodeId v <-> colon <-> text (showDotRuleCaseName ru) <> (if null lbl
1043	/// then mempty else brackets (vcat (punctuate comma lbl)))`. `<->` is
1044	/// space-separated (`#i : name`) but the action bracket is joined with `<>`
1045	/// (NO space before `[`), and the actions stack VERTICALLY (`vcat`,
1046	/// comma-punctuated) when there are several. Actions are filtered exactly
1047	/// as HS (`is_not_diff_annotation`; drop `AUTO_*` only when
1048	/// `goShowAutoSource`).  The caller lays this Doc out via
1049	/// `render_balanced` (HS `asM = renderRow [(Nothing, ruleLabel)]`,
1050	/// Dot.hs:320-322 — a single-doc row, i.e. width 130 / ribbon 87).
1051	fn rule_label_doc(nid: &LVar, ru: &RuleACInst, opts: &GraphOptions) -> Doc {
1052	    let act_docs: Vec<Doc> = ru.actions.iter()
1053	        .filter(|fa| is_not_diff_annotation(ru, fa))
1054	        .filter(|fa| !opts.show_auto_source || !is_auto_source(fa))
1055	        .map(fact_doc_of)
1056	        .collect();
1057	    // `prettyNodeId v <-> colon <-> text name` — three same-line text
1058	    // tokens joined by single spaces; layout-equivalent to one fused text
1059	    // run of the same width (no break points inside a `<>`/`<+>` chain).
1060	    let header = Doc::text(format!("{} : {}", nid, rule_case_name(ru)));
1061	    if act_docs.is_empty() {
1062	        header
1063	    } else {
1064	        // `brackets (vcat $ punctuate comma lbl)` (Dot.hs:338).
1065	        header
1066	            .beside(Doc::text("["))
1067	            .beside(pretty_hpj::vcat(pretty_hpj::punctuate(
1068	                Doc::text(","), act_docs)))
1069	            .beside(Doc::text("]"))
1070	    }
1071	}
