1099	/// Mirror Haskell `trimSapicName` (Theory/Model/Rule.hs:1175-1185): strips a
1100	/// trailing `_<digits>_<digits>` suffix from a SAPiC rule name.
1101	fn trim_sapic_name(name: &str) -> String {
1102	    // splitString: reverse (splitOn "_" name); if >= 3 parts, the prefix is
1103	    // intercalate "_" (reverse (drop 2 parts)), and the last two parts are
1104	    // parts[1] (n) and parts[0] (m).
1105	    let parts: Vec<&str> = name.split('_').collect();
1106	    if parts.len() >= 3 {
1107	        let m = parts[parts.len() - 1];
1108	        let n = parts[parts.len() - 2];
1109	        // Haskell `all isDigit s` is True for the empty string too.
1110	        let all_digits = |s: &str| s.chars().all(|c| c.is_ascii_digit());
1111	        if all_digits(n) && all_digits(m) {
1112	            return parts[..parts.len() - 2].join("_");
1113	        }
1114	    }
1115	    name.to_string()
1116	}
