1214	/// HS `nodeColorMap.groupIdx` (Dot.hs:196-200): partition a rule into one of
1215	/// four colour groups. Guard order matters and mirrors HS exactly:
1216	///   * `isDestrRule` (DestrRule or IEqualityRule)               → 0
1217	///   * `isConstrRule` (Constr/Fresh/Pub/Nat constr or Coerce)   → 2
1218	///   * `isFreshRule` (proto `Fresh`) or `isISendRule`           → 3
1219	///   * otherwise (protocol rules, IRecv, …)                     → 1
1220	fn group_idx(ru: &RuleACInst) -> usize {
1221	    use tamarin_theory::rule::{
1222	        is_coerce_rule_info, is_constr_rule_info, is_destr_rule_info,
1223	        is_fresh_constr_rule_info, is_iequality_rule_info, is_isend_rule_info,
1224	        is_nat_constr_rule_info, is_pub_constr_rule_info,
1225	    };
1226	    match &ru.info {
1227	        RuleInfo::Intr(i) => {
1228	            if is_destr_rule_info(i) || is_iequality_rule_info(i) {
1229	                0
1230	            } else if is_constr_rule_info(i)
1231	                || is_fresh_constr_rule_info(i)
1232	                || is_pub_constr_rule_info(i)
1233	                || is_nat_constr_rule_info(i)
1234	                || is_coerce_rule_info(i)
1235	            {
1236	                2
1237	            } else if is_isend_rule_info(i) {
1238	                3
1239	            } else {
1240	                1
1241	            }
1242	        }
1243	        // `isDestrRule`/`isConstrRule`/`isISendRule` are all intruder-only, so
1244	        // a protocol rule only ever hits `isFreshRule` (the reserved `Fresh`
1245	        // rule) → 3, else the `otherwise` group → 1.
1246	        RuleInfo::Proto(p) => {
1247	            if p.name == ProtoRuleName::Fresh { 3 } else { 1 }
1248	        }
1249	    }
1250	}
