1252	/// Faithful port of HS `nodeColorMap` (Dot.hs:190-218).
1253	///
1254	/// HS: `M.fromList [ (get rInfo ru, getColorForRule (ruleAttributes ru) gIdx
1255	/// mIdx) | (gIdx, grp) <- groups, (mIdx, ru) <- zip [0..] grp ]`, with the
1256	/// four `groups` filtered from `rules` by [`group_idx`] and coloured via
1257	/// `colors = lightColorGroups intruderHue (map (length . snd) groups)` and
1258	/// `intruderHue = 18 % 360` (Dot.hs:208,217-218).
1259	///
1260	/// `rules` here is `M.elems $ get sNodes se` (Dot.hs:485) — the raw system's
1261	/// nodes in NodeId order — so we sort by NodeId (`M.Map` key order) first.
1262	/// Each entry's colour follows `getColorForRule attrs gIdx mIdx = fromMaybe
1263	/// defaultColor (ruleColor attrs)` (Dot.hs:212): a rule with an explicit
1264	/// `color:` attribute maps to THAT colour, otherwise to the palette default
1265	/// (`defaultColor = hsvToRGB (getColor (gIdx, mIdx))`, Dot.hs:214).  This map
1266	/// value is what `dotNodeCompact` feeds to `colorUsesWhiteFont` (Dot.hs:255,
1267	/// 258) to pick a node's font colour — so a SAPiC rule with a dark `color:`
1268	/// attribute must map to that dark colour (→ white font), not to the light
1269	/// palette default.  (The FILL colour is resolved separately via
1270	/// `explicit_rule_color` at the call site, so carrying the explicit colour
1271	/// here changes only the font decision, never the fill.)
1272	fn build_node_color_map(nodes: &[(NodeId, RuleACInst)]) -> NodeColorMap<'_> {
1273	    use tamarin_utils::color::{hsv_to_rgb, light_color_groups, Hsv, Rgb};
1274	
1275	    // `M.elems $ get sNodes se`: iterate in NodeId (Map key) order.
1276	    let mut ordered: Vec<&(NodeId, RuleACInst)> = nodes.iter().collect();
1277	    ordered.sort_by(|a, b| a.0.cmp(&b.0));
1278	
1279	    // `groups = [ (gIdx, [ru | ru <- rules, gIdx == groupIdx ru]) | gIdx <- 0..3 ]`
1280	    // — order-preserving partition into four groups.
1281	    let mut groups: [Vec<&RuleACInst>; 4] =
1282	        [Vec::new(), Vec::new(), Vec::new(), Vec::new()];
1283	    for pair in &ordered {
1284	        let ru = &pair.1;
1285	        groups[group_idx(ru)].push(ru);
1286	    }
1287	    let sizes: [usize; 4] =
1288	        [groups[0].len(), groups[1].len(), groups[2].len(), groups[3].len()];
1289	
1290	    // `colors = M.fromList $ lightColorGroups intruderHue (map (length . snd)
1291	    // groups)`, `intruderHue = 18 % 360`. The palette is exact `Rational` in
1292	    // HS; the f64 port matches `rgbToHex`'s `floor(256*f)` quantisation for all
1293	    // realistic group sizes (verified: 0/4.28M hex divergences).
1294	    const INTRUDER_HUE: f64 = 18.0 / 360.0;
1295	    let palette = light_color_groups(INTRUDER_HUE, &sizes);
1296	    let get_color = |gi: usize, mi: usize| -> Hsv {
1297	        palette.iter()
1298	            .find(|((g, m), _)| *g == gi && *m == mi)
1299	            .map(|(_, hsv)| *hsv)
1300	            // `getColor idx = fromMaybe (HSV 0 1 1) (M.lookup idx colors)`
1301	            // (Dot.hs:209) — unreachable for a valid (gIdx, mIdx).
1302	            .unwrap_or_else(|| Hsv::new(0.0, 1.0, 1.0))
1303	    };
1304	
1305	    let mut entries: Vec<(&RInfo, Rgb)> = Vec::new();
1306	    for (gi, grp) in groups.iter().enumerate() {
1307	        for (mi, ru) in grp.iter().enumerate() {
1308	            // `getColorForRule attrs gIdx mIdx = fromMaybe defaultColor
1309	            // (ruleColor attrs)` (Dot.hs:212): explicit `color:` wins, else the
1310	            // palette default.  `ruleAttributes ru = praciAttributes` for a
1311	            // RuleACInst (Rule.hs:674) — the same attributes `explicit_rule_color`
1312	            // reads, so a coloured rule maps to its own dark fill colour.
1313	            let color = match &ru.info {
1314	                RuleInfo::Proto(p) => {
1315	                    p.attributes.color.unwrap_or_else(|| hsv_to_rgb(get_color(gi, mi)))
1316	                }
1317	                _ => hsv_to_rgb(get_color(gi, mi)),
1318	            };
1319	            entries.push((&ru.info, color));
1320	        }
1321	    }
1322	    NodeColorMap { entries }
1323	}
