1416	/// Port of Haskell `roleColor` (Dot.hs:534-544): a deterministic per-role
1417	/// `#RRGGBBAA` colour. `simpleHash name = foldl (\acc c -> acc*31 + ord c) 7`
1418	/// over the role's base name (Haskell `Int`, i.e. 64-bit two's-complement
1419	/// wrapping), `generateValue = (hash `mod` 360) / 360` (Haskell `mod` is
1420	/// non-negative for a positive divisor — `rem_euclid` here), then
1421	/// `hsvToRGB (HSV (v*360) 0.75 0.85)` with each channel `floor(f*255)` and a
1422	/// fixed alpha `floor(255*0.3) = 76`. Hex digits are UPPERCASE (`%02X`), and
1423	/// the channel scale is `*255` (not `*256` as in `rgb_to_hex`), so this does
1424	/// not reuse `rgb_to_hex`.
1425	fn role_color(name: &str) -> String {
1426	    // simpleHash: `Int` arithmetic, wraps on overflow.
1427	    let hash: i64 = name.chars().fold(7i64, |acc, c| {
1428	        acc.wrapping_mul(31).wrapping_add(c as i64)
1429	    });
1430	    let v = (hash.rem_euclid(360)) as f64 / 360.0;
1431	    let rgb = tamarin_utils::color::hsv_to_rgb(
1432	        tamarin_utils::color::Hsv::new(v * 360.0, 0.75, 0.85));
1433	    let chan = |f: f64| -> i64 { (f * 255.0).floor() as i64 };
1434	    let alpha: i64 = (255.0 * 0.3_f64).floor() as i64; // = 76
1435	    format!("#{:02X}{:02X}{:02X}{:02X}",
1436	        chan(rgb.r), chan(rgb.g), chan(rgb.b), alpha)
1437	}
