1439	/// Escape a record FIELD's text, mirroring HS `Text.Dot.renderRecord`'s
1440	/// `escape` (Text/Dot.hs:273-280): exactly the record metacharacters
1441	/// `| { } < >` get a backslash — NOT `"` / `\` / newline, which are handled
1442	/// once at the attribute level by `showAttr` (see `escape_dot_label`).
1443	fn escape_record_field(s: &str) -> String {
1444	    let mut out = String::with_capacity(s.len());
1445	    for c in s.chars() {
1446	        match c {
1447	            '|' => out.push_str("\\|"),
1448	            '{' => out.push_str("\\{"),
1449	            '}' => out.push_str("\\}"),
1450	            '<' => out.push_str("\\<"),
1451	            '>' => out.push_str("\\>"),
1452	            _   => out.push(c),
1453	        }
1454	    }
1455	    out
1456	}
1457	
1458	/// Escape a Graphviz attribute VALUE, mirroring HS `Text.Dot.showAttr`
1459	/// (Text/Dot.hs:346-353): only `"` (→ `\"`) and newline (→ `\l`, graphviz's
1460	/// left-justified line break) are escaped.  This is the LAST escaping pass
1461	/// for every label — plain ellipse labels (where record metacharacters
1462	/// `{ } | < >` must stay literal) and record labels (whose field text was
1463	/// already record-escaped by `escape_record_field`) alike.
1464	fn escape_dot_label(s: &str) -> String {
1465	    let mut out = String::with_capacity(s.len());
1466	    for c in s.chars() {
1467	        match c {
1468	            '"'  => out.push_str("\\\""),
1469	            '\n' => out.push_str("\\l"),
1470	            _    => out.push(c),
1471	        }
1472	    }
1473	    out
1474	}
